1	`ifndef HDL_VERILOG_RVV_DESIGN_RVV_SVH
2	`include "rvv_backend.svh"
3	`endif
4	
5	module rvv_backend_retire(
6	  rob2rt_write_valid,
7	  rob2rt_write_data,
8	  rt2rob_write_ready,
9	  rt2xrf_write_valid,
10	  rt2rvs_write_data,
11	  rvs2rt_write_ready,
12	`ifdef ZVE32F_ON
13	  rt2frf_write_valid,
14	  frf2rt_write_ready,
15	`endif
16	  rt2vrf_write_valid,
17	  rt2vrf_write_data,
18	  rt2vcsr_write_valid,
19	  rt2vcsr_write_data,
20	  vcsr2rt_write_ready,
21	  rt2vxsat_write_valid,
22	  rt2vxsat_write_data,
23	  vxsat2rt_write_ready
24	`ifdef ZVE32F_ON
25	  ,rt2fcsr_write_valid,
26	  rt2fcsr_write_data,
27	  fcsr2rt_write_ready
28	`endif
29	`ifdef TB_SUPPORT
30	  ,vrf_data,
31	  rt2rvvi_valid,
32	  rt2rvvi_data
33	`endif
34	);
35	// ROB dataout
36	    input   logic    [`NUM_RT_UOP-1:0]            rob2rt_write_valid;
37	    input   ROB2RT_t [`NUM_RT_UOP-1:0]            rob2rt_write_data;
38	    output  logic    [`NUM_RT_UOP-1:0]            rt2rob_write_ready;
39	
40	// write back to XRF
41	    output  logic    [`NUM_RT_UOP-1:0]            rt2xrf_write_valid;
42	    output  RT2RVS_t [`NUM_RT_UOP-1:0]            rt2rvs_write_data;
43	    input   logic    [`NUM_RT_UOP-1:0]            rvs2rt_write_ready;
44	
45	// write back to FRF
46	`ifdef ZVE32F_ON
47	    output  logic    [`NUM_RT_UOP-1:0]            rt2frf_write_valid;
48	    input   logic    [`NUM_RT_UOP-1:0]            frf2rt_write_ready;
49	`endif
50	
51	// write back to VRF
52	    output  logic    [`NUM_RT_UOP-1:0]            rt2vrf_write_valid;
53	    output  RT2VRF_t [`NUM_RT_UOP-1:0]            rt2vrf_write_data;
54	
55	// write to update vcsr
56	    output  logic                                 rt2vcsr_write_valid;
57	    output  RVVConfigState                        rt2vcsr_write_data;
58	    input   logic                                 vcsr2rt_write_ready;
59	
60	// vxsat
61	    output  logic                                 rt2vxsat_write_valid;
62	    output  logic   [`VCSR_VXSAT_WIDTH-1:0]       rt2vxsat_write_data;
63	    input   logic                                 vxsat2rt_write_ready;
64	
65	`ifdef ZVE32F_ON
66	// Floating-point exception
67	    output  logic                                 rt2fcsr_write_valid;
68	    output  RVFEXP_t                              rt2fcsr_write_data;
69	    input   logic                                 fcsr2rt_write_ready;
70	`endif
71	
72	`ifdef TB_SUPPORT
73	// Retire information for RVVI.
74	    input   logic    [`NUM_VRF-1:0][`VLEN-1:0]    vrf_data;
75	    output  logic    [`NUM_RT_UOP-1:0]            rt2rvvi_valid; // always ready to receive.
76	    output  ROB2RT_t [`NUM_RT_UOP-1:0]            rt2rvvi_data;  
77	`endif
78	
79	////////////Wires & Regs  ///////////////
80	logic [`NUM_RT_UOP-1:0]                           w_valid_chkTrap;
81	logic [`NUM_RT_UOP-1:0][`VLENB-1:0]               w_strobe;
82	logic [`NUM_RT_UOP-1:0][`REGFILE_INDEX_WIDTH-1:0] w_addr;
83	logic [`NUM_RT_UOP-1:0]                           w_valid;
84	logic [`NUM_RT_UOP-1:0][`VLEN-1:0]                w_data;
85	logic [`NUM_RT_UOP-1:0]                           trap_flag;
86	RVVConfigState  [`NUM_RT_UOP-1:0]                 w_vcsr;
87	logic [`NUM_RT_UOP-1:0][`VLENB-1:0]               w_vxsaturate;
88	logic [`NUM_RT_UOP-1:0][`VCSR_VXSAT_WIDTH-1:0]    w_vxsat;
89	`ifdef ZVE32F_ON
90	logic [`NUM_RT_UOP-1:0][`VLENB-1:0]               fpexp_nv_lanes;
91	logic [`NUM_RT_UOP-1:0][`VLENB-1:0]               fpexp_dz_lanes;
92	logic [`NUM_RT_UOP-1:0][`VLENB-1:0]               fpexp_of_lanes;
93	logic [`NUM_RT_UOP-1:0][`VLENB-1:0]               fpexp_uf_lanes;
94	logic [`NUM_RT_UOP-1:0][`VLENB-1:0]               fpexp_nx_lanes;
95	logic [`NUM_RT_UOP-1:0]                           fpexp_nv;
96	logic [`NUM_RT_UOP-1:0]                           fpexp_dz;
97	logic [`NUM_RT_UOP-1:0]                           fpexp_of;
98	logic [`NUM_RT_UOP-1:0]                           fpexp_uf;
99	logic [`NUM_RT_UOP-1:0]                           fpexp_nx;
100	RVFEXP_t  [`NUM_RT_UOP-1:0]                       w_fpexp;
101	logic     [`NUM_RT_UOP-1:0]                       w_fpexp_vld;
102	logic     [`NUM_RT_UOP-1:0]                       fcsr2rt_ready;
103	`endif
104	logic [`NUM_RT_UOP-1:1][`NUM_RT_UOP-1:0]          waw;
105	logic [`NUM_RT_UOP-1:0]                           hit_waw;
106	logic [`NUM_RT_UOP-1:0]                           vrfres_valid;
107	logic [`NUM_RT_UOP-1:0][`VLEN-1:0]                vrfres;
108	logic [`NUM_RT_UOP-1:0][`VLENB-1:0]               vrfres_strobe;
109	logic [`NUM_RT_UOP-1:0]                           w_vrf_valid;
110	logic [`NUM_RT_UOP-1:0]                           w_vrf;
111	logic [`NUM_RT_UOP-1:0]                           w_xrf_valid;
112	logic [`NUM_RT_UOP-1:0]                           w_xrf;
113	`ifdef ZVE32F_ON
114	logic [`NUM_RT_UOP-1:0]                           w_frf_valid;
115	logic [`NUM_RT_UOP-1:0]                           w_frf;
116	`endif
117	logic [`NUM_RT_UOP-1:0]                           vxsat2rt_ready;
118	
119	genvar                                            i,j;
120	
121	/////////////////////////////////
122	/////////////Main////////////////
123	/////////////////////////////////
124	generate
125	  for(j=0;j<`NUM_RT_UOP;j++) begin : gen_inter_logic
126	    assign w_addr[j]    = rob2rt_write_data[j].w_index;
127	    assign w_valid[j]   = rob2rt_write_data[j].w_valid;
128	    assign w_data[j]    = rob2rt_write_data[j].w_data;
129	    assign trap_flag[j] = rob2rt_write_data[j].trap_flag;
130	    assign w_vcsr[j]    = rob2rt_write_data[j].vector_csr;
131	
132	    for (i=0;i<`VLENB;i++) begin : gen_vlenb
133	      assign w_strobe[j][i]       = rob2rt_write_data[j].vd_type[i]==BODY_ACTIVE;
134	      assign w_vxsaturate[j][i]   = w_strobe[j][i] & rob2rt_write_data[j].vxsaturate[i];
135	      `ifdef ZVE32F_ON
136	      assign fpexp_nv_lanes[j][i] = w_strobe[j][i] & rob2rt_write_data[j].fpexp[i].nv; 
137	      assign fpexp_dz_lanes[j][i] = w_strobe[j][i] & rob2rt_write_data[j].fpexp[i].dz; 
138	      assign fpexp_of_lanes[j][i] = w_strobe[j][i] & rob2rt_write_data[j].fpexp[i].of; 
139	      assign fpexp_uf_lanes[j][i] = w_strobe[j][i] & rob2rt_write_data[j].fpexp[i].uf; 
140	      assign fpexp_nx_lanes[j][i] = w_strobe[j][i] & rob2rt_write_data[j].fpexp[i].nx; 
141	      `endif
142	    end
143	
144	    assign w_vxsat[j]     = |w_vxsaturate[j];
145	    `ifdef ZVE32F_ON
146	    assign fpexp_nv[j]    = |fpexp_nv_lanes[j];
147	    assign fpexp_dz[j]    = |fpexp_dz_lanes[j];
148	    assign fpexp_of[j]    = |fpexp_of_lanes[j];
149	    assign fpexp_uf[j]    = |fpexp_uf_lanes[j];
150	    assign fpexp_nx[j]    = |fpexp_nx_lanes[j];
151	    assign w_fpexp[j].nv  = fpexp_nv[j];
152	    assign w_fpexp[j].dz  = fpexp_dz[j];
153	    assign w_fpexp[j].of  = fpexp_of[j];
154	    assign w_fpexp[j].uf  = fpexp_uf[j];
155	    assign w_fpexp[j].nx  = fpexp_nx[j];
156	    assign w_fpexp_vld[j] = |w_fpexp[j];
157	    `endif
158	
159	    if(j==0) begin : gen_0
160	      assign w_valid_chkTrap[0] = !trap_flag[0] && rob2rt_write_valid[0];
161	    end else begin : gen_j
162	      assign w_valid_chkTrap[j] = !(|trap_flag[j-1:0]) && rob2rt_write_valid[j];
163	    end
164	
165	  // writing different register
166	    assign w_vrf[j]       = (rob2rt_write_data[j].w_type==VRF) && rob2rt_write_data[j].w_valid;
167	    assign w_vrf_valid[j] = w_valid_chkTrap[j] && w_vrf[j];
168	    assign w_xrf[j]       = (rob2rt_write_data[j].w_type==XRF) && rob2rt_write_data[j].w_valid;
169	    assign w_xrf_valid[j] = w_valid_chkTrap[j] && w_xrf[j];
170	  `ifdef ZVE32F_ON
171	    assign w_frf[j]       = (rob2rt_write_data[j].w_type==FRF) && rob2rt_write_data[j].w_valid;
172	    assign w_frf_valid[j] = w_valid_chkTrap[j] && w_frf[j];
173	  `endif
174	  end
175	
176	// VRF WAW
177	  assign vrfres[0]        = w_data[0];
178	  assign vrfres_strobe[0] = w_strobe[0];
179	
180	  for(j=1;j<`NUM_RT_UOP;j++) begin: process_waw
181	    rvv_backend_retire_waw #(
182	      .UOP_NUM    (j+1)
183	    ) u_process_waw (
184	      .valid      (w_vrf_valid[j:0]&rt2rob_write_ready[j:0]),
185	      .w_index    (w_addr[j:0]),
186	      .w_strobe   (w_strobe[j:0]),
187	      .w_data     (w_data[j:0]),
188	      .waw        (waw[j]),
189	      .res        (vrfres[j]),
190	      .res_strobe (vrfres_strobe[j])
191	    );
192	  end
193	
194	  always_comb begin
195	    hit_waw = 'b0;
196	    for(int i=1;i<`NUM_RT_UOP;i++) begin
197	      hit_waw = hit_waw | waw[i];
198	    end
199	  end
200	  
201	  // mask the existing WAW uop
202	  assign vrfres_valid = w_vrf_valid & rt2rob_write_ready & (~hit_waw);
203	
204	// retire
205	  // To VCSR
206	  assign rt2vcsr_write_valid  = rob2rt_write_valid[0] && trap_flag[0] && vcsr2rt_write_ready;
207	  assign rt2vcsr_write_data   = w_vcsr[0];
208	
209	  // To vxsat
210	  assign vxsat2rt_ready       = ~(w_vrf_valid&w_vxsat) | {`NUM_RT_UOP{vxsat2rt_write_ready}}; 
211	  assign rt2vxsat_write_valid = |(w_vrf_valid&rt2rob_write_ready&w_vxsat) && !trap_flag[0];
212	  assign rt2vxsat_write_data  = rt2vxsat_write_valid;
213	
214	`ifdef ZVE32F_ON
215	  // To FCSR[4:0]
216	  assign fcsr2rt_ready          = ~w_fpexp_vld | {`NUM_RT_UOP{fcsr2rt_write_ready}};
217	  assign rt2fcsr_write_valid    = trap_flag[0] ? 'b0 : |(w_fpexp_vld & rob2rt_write_valid & rt2rob_write_ready);
218	  assign rt2fcsr_write_data.nv  = |(fpexp_nv & rob2rt_write_valid & rt2rob_write_ready);
219	  assign rt2fcsr_write_data.dz  = |(fpexp_dz & rob2rt_write_valid & rt2rob_write_ready);
220	  assign rt2fcsr_write_data.of  = |(fpexp_of & rob2rt_write_valid & rt2rob_write_ready);
221	  assign rt2fcsr_write_data.uf  = |(fpexp_uf & rob2rt_write_valid & rt2rob_write_ready);
222	  assign rt2fcsr_write_data.nx  = |(fpexp_nx & rob2rt_write_valid & rt2rob_write_ready);
223	`endif
224	  
225	  always_comb begin
226	    if(trap_flag[0])
227	      rt2rob_write_ready[0] = vcsr2rt_write_ready;
228	    else if(rob2rt_write_data[0].w_type==VRF) begin
229	      rt2rob_write_ready[0] = vxsat2rt_ready[0]
230	                              `ifdef ZVE32F_ON
231	                              && fcsr2rt_ready[0]
232	                              `endif
233	                              ;
234	    end
235	    else begin
236	    `ifdef ZVE32F_ON
237	      rt2rob_write_ready[0] = (rob2rt_write_data[0].w_type==XRF) ? rvs2rt_write_ready[0] : frf2rt_write_ready[0] & fcsr2rt_ready[0];
238	    `else
239	      rt2rob_write_ready[0] = rvs2rt_write_ready[0];
240	    `endif
241	    end
242	  end
243	
244	  for(j=1;j<`NUM_RT_UOP;j++) begin
245	    always_comb begin
246	      if(rob2rt_write_data[j].w_type==VRF) begin
247	        rt2rob_write_ready[j] = rt2rob_write_ready[j-1] & (vxsat2rt_ready[j]
248	                                                          `ifdef ZVE32F_ON
249	                                                          && fcsr2rt_ready[j]
250	                                                          `endif
251	                                                          );
252	      end
253	      else begin
254	      `ifdef ZVE32F_ON
255	        rt2rob_write_ready[j] = (rob2rt_write_data[j].w_type==XRF) 
256	                                ? rt2rob_write_ready[j-1] & rvs2rt_write_ready[j] 
257	                                : rt2rob_write_ready[j-1] & frf2rt_write_ready[j] & fcsr2rt_ready[j];
258	      `else
259	        rt2rob_write_ready[j] = rt2rob_write_ready[j-1] & rvs2rt_write_ready[j];
260	      `endif
261	      end
262	    end
263	  end
264	
265	  for(j=0;j<`NUM_RT_UOP;j++) begin : gen_rt2vrf_write
266	    always_comb begin
267	      if(vrfres_valid[j]) begin
268	        rt2vrf_write_valid[j]           = 1'b1; 
269	
270	        `ifdef TB_SUPPORT
271	        rt2vrf_write_data[j].uop_pc     = rob2rt_write_data[j].uop_pc;
272	        `endif
273	        rt2vrf_write_data[j].rt_index   = w_addr[j];
274	        rt2vrf_write_data[j].rt_data    = vrfres[j];
275	        rt2vrf_write_data[j].rt_strobe  = vrfres_strobe[j];
276	      end
277	      else begin
278	        rt2vrf_write_valid[j]           = 'b0;     
279	        rt2vrf_write_data[j]            = 'b0;
280	      end
281	    end
282	  end
283	
284	  for(j=0;j<`NUM_RT_UOP;j++) begin : gen_rt2rob_write
285	    always_comb begin
286	      `ifdef ZVE32F_ON
287	      if(rt2rob_write_ready[j]&(w_xrf[j]|w_frf[j])) begin
288	      `else
289	      if(rt2rob_write_ready[j]&w_xrf[j]) begin
290	      `endif
291	        rt2xrf_write_valid[j]           = w_xrf[j];     
292	        `ifdef ZVE32F_ON
293	        rt2frf_write_valid[j]           = w_frf[j]; 
294	        `endif
295	
296	        `ifdef TB_SUPPORT
297	        rt2rvs_write_data[j].uop_pc     = rob2rt_write_data[j].uop_pc;
298	        `endif
299	        rt2rvs_write_data[j].rt_index   = w_addr[j];
300	        rt2rvs_write_data[j].rt_data    = w_data[j][31:0];
301	      end
302	      else begin
303	        rt2xrf_write_valid[j]           = 'b0;     
304	        `ifdef ZVE32F_ON
305	        rt2frf_write_valid[j]           = 'b0; 
306	        `endif
307	        rt2rvs_write_data[j]            = 'b0;
308	      end
309	    end
310	  end
311	endgenerate
312	
313	`ifdef TB_SUPPORT
314	// retire infomation for RVVI
315	  assign rt2rvvi_valid = rob2rt_write_valid&rt2rob_write_ready;
316	
317	  always_comb begin
318	    for(int j=0;j<`NUM_RT_UOP;j++) begin
319	      rt2rvvi_data[j]         = rob2rt_write_data[j];
320	      rt2rvvi_data[j].w_valid = rob2rt_write_data[j].w_valid&rt2rvvi_valid[j];  // coral.scalar core use w_valid instead of rt2rvvi_valid
321	
322	      if(rob2rt_write_data[j].w_type==VRF) begin
323	        for(int i=0;i<`VLENB;i++) begin
324	          rt2rvvi_data[j].vd_type                             = {`VLENB{BODY_ACTIVE}};
325	          rt2rvvi_data[j].w_data[i*`BYTE_WIDTH+:`BYTE_WIDTH]  = vrfres_strobe[j][i] 
326	                                                                ? vrfres[j][i*`BYTE_WIDTH+:`BYTE_WIDTH] 
327	                                                                : vrf_data[rob2rt_write_data[j].w_index][i*`BYTE_WIDTH+:`BYTE_WIDTH];
328	        end
329	      end
330	    end
331	  end
332	`endif
333	
334	endmodule
335

