83	
84	// Enum to encode the major opcode of the instruction. See "Section 5. Vector
85	// Instruction Formats" of the RVV 1.0 spec.
86	typedef enum logic [1:0] {
87	  LOAD=0,
88	  STORE=1,
89	  RVV=2
90	} RVVOpCode;
91	
92	// A decoded instruction forwarded to the RVVCore from the scalar core.
93	typedef struct packed {
94	  logic [`PC_WIDTH-1:0] pc;
95	  RVVOpCode             opcode;   // effectively bits [6:0] from instruction
96	  logic [24:0]          bits;     // bits [31:7] from instruction
97	} RVVInstruction;
98	
99	// An command internal to the RVVCore. The immediate value of this command has
100	// been read from the scalar register file if necessary. It also contains
101	// additional data to track configuration register state (ie: SEW, LMUL, etc).
102	typedef struct packed {
103	`ifdef TB_SUPPORT
104	  logic [`PC_WIDTH-1:0] inst_pc;
105	`endif
106	  RVVOpCode             opcode;
107	  logic [24:0]          bits;
108	  logic [31:0]          rs1;
109	  RVVConfigState        arch_state;
110	} RVVCmd;
111	
112	//
113	// DE stage, Command Queue to Uops Queue
114	//
115	// Effective MUL enum
116	typedef enum logic [3:0] {
117	  EMUL1=0,
118	  EMUL2=1,
119	  EMUL4=2,
120	  EMUL8=3,
121	  EMUL3,
122	  EMUL5,
123	  EMUL6,
124	  EMUL7,
125	  EMUL_NONE     // it means this is not supported 
126	} EMUL_e;
127	
128	// Effective Element Width
129	typedef enum logic [2:0] {
130	  EEW_NONE,    // it means this is not supported 
131	  EEW1,
132	  EEW8, 
133	  EEW16,
134	  EEW32,
135	  EEW64
136	} EEW_e;
137	
138	// the legal RVVCmd after decoding
139	typedef struct packed {
140	  RVVCmd                          cmd;
141	  EEW_e                           eew_vs1;
142	  EEW_e                           eew_vs2;
143	  EEW_e                           eew_vd;
144	  EEW_e                           eew_max;
145	  EMUL_e                          emul_vs1;
146	  EMUL_e                          emul_vs2;
147	  EMUL_e                          emul_vd;
148	  EMUL_e                          emul_max;
149	  logic   [`UOP_INDEX_WIDTH-1:0]  uop_vstart;         
150	  logic   [`UOP_INDEX_WIDTH-1:0]  uop_index_max;         
151	  logic   [`VL_WIDTH-1:0]         evl;
152	  logic                           force_vma_agnostic;
153	  logic                           force_vta_agnostic;
154	} LCMD_t;
155	
156	// execution unit
157	typedef enum logic [3:0] {
158	  ALU,
159	  MUL,
160	  MAC,
161	  PMT,
162	  RDT,
163	  CMP,
164	  DIV,
165	  LSU,
166	`ifdef ZVE32F_ON
167	  FMA,
168	  FCVT,
169	  FRDT,
170	  FNCMP,
171	  FCMP,
172	  FDIV,
173	  FTBL,
174	`endif
175	  MISC
176	} EXE_UNIT_e;
177	
178	// when EXE_UNIT_e is LSU, it identifys what LSU instruction, unit-stride load or indexed store or ..? based on inst_encoding[31:26]
179	typedef enum logic [1:0] {
180	  US,         // Unit-Stride
181	  IU,         // Indexed Unordered
182	  CS,         // Constant Stride
183	  IO          // Indexed Ordered
184	} LSU_MOP_e;
185	
186	// It identifys what unit-stride instruction when LSU_MOP_e=US, based on inst_encoding[24:20]
187	typedef enum logic [1:0] {
188	  US_US,         // Unit-Stride load/store
189	  US_WR,         // Whole Register load/store
190	  US_MK,         // MasK load/store, EEW=8(inst_encoding[14:12]=3'b000)
191	  US_FF          // Faul-only-First load
192	} LSU_UMOP_e;
193	
194	// It identifys what inst_encoding[11:7] is used for when LSU instruction, based on inst_encoding[5]
195	typedef enum logic [0:0] {
196	  IS_LOAD,       
197	  IS_STORE       
198	} LSU_IS_STORE_e;
