201	typedef enum logic [0:0] {
202	  IS_SEGMENT,
203	  NONE      
204	} LSU_IS_SEG_e;
205	
206	// combine those signals to LSU_TYPE
207	typedef struct packed {
208	  LSU_MOP_e         lsu_mop;
209	  LSU_UMOP_e        lsu_umop;
210	  LSU_IS_STORE_e    lsu_is_store;
211	  LSU_IS_SEG_e      lsu_is_seg;
212	} LSU_TYPE_t;
213	
214	// function opcode
215	typedef union packed {
216	  logic   [`FUNCT6_WIDTH-1:0]         ari_funct6;
217	  LSU_TYPE_t                          lsu_funct6;
218	} FUNCT6_u;
219	
220	// uop classification used for dispatch rule
221	typedef enum logic [2:0] {
222	  XXX=0,
223	  XXV=1,
224	  XVX=2,
225	  XVV=3,
226	  VXX=4,
227	  VXV=5,
228	  VVX=6,
229	  VVV=7
230	} UOP_CLASS_e;
231	
232	// Destination data struct
233	`ifdef ZVE32F_ON
234	typedef enum logic [1:0] {
235	`else
236	typedef enum logic [0:0] {
237	`endif
238	  VRF,
239	  XRF
240	`ifdef ZVE32F_ON
241	  ,FRF
242	`endif
243	} W_DATA_TYPE_e;
244	
245	// the uop struct stored in Uops Queue
246	typedef struct packed {
247	`ifdef TB_SUPPORT
248	  logic   [`PC_WIDTH-1:0]             uop_pc;
249	  logic                               res_updating_end; 
250	`endif
251	  logic   [`FUNCT3_WIDTH-1:0]         uop_funct3;
252	  FUNCT6_u                            uop_funct6;
253	  EXE_UNIT_e                          uop_exe_unit; 
254	  UOP_CLASS_e                         uop_class;   
255	  RVVConfigState                      vector_csr;  
256	  logic   [`VL_WIDTH-1:0]             vs_evl;             
257	  logic                               ignore_vma;
258	  logic                               ignore_vta;
259	  logic                               force_vma_agnostic; 
260	  logic                               force_vta_agnostic; 
261	  logic                               vm;                 
262	  logic                               v0_valid;           
263	  logic   [`REGFILE_INDEX_WIDTH-1:0]  dst_index;
264	  EEW_e                               vd_eew;  
265	  logic                               vd_valid;
266	  logic                               vs3_valid;          
267	  logic                               xd_valid; 
268	`ifdef ZVE32F_ON
269	  logic                               fd_valid; 
270	`endif
271	  logic   [`REGFILE_INDEX_WIDTH-1:0]  vs1;              
272	  EEW_e                               vs1_eew;            
273	  logic                               vs1_valid;
274	  logic   [`REGFILE_INDEX_WIDTH-1:0]  vs2_index; 	        
275	  EEW_e                               vs2_eew;
276	  logic                               vs2_valid;
277	  logic   [`XLEN-1:0] 	              rs1_data;           
278	  logic        	                      rs1_data_valid;                                
279	  logic   [`UOP_INDEX_WIDTH-1:0]      uop_index;          
280	  logic                               first_uop_valid;    
281	  logic                               last_uop_valid;     
282	  logic   [$clog2(`EMUL_MAX)-1:0]     seg_field_index;    
283	  logic                               pshrob_valid;       
284	  logic                               pshlsu_valid;
285	} UOP_QUEUE_t;    
286	
287	// specify whether the current byte belongs to 'prestart' or 'body-inactive' or 'body-active' or 'tail'
288	typedef enum logic [1:0] {
289	  NOT_CHANGE    = 2'b00,      // the byte is not changed, which may belong to 'prestart' or superfluous element in widening/narrowing uop
290	  TAIL          = 2'b01,      // tail byte
291	  BODY_INACTIVE = 2'b10,      // body-inactive byte
292	  BODY_ACTIVE   = 2'b11       // body-active byte
293	} BYTE_TYPE_e;
294	
295	// trap handle
296	typedef enum logic [1:0] {
297	  TRAP_LSU,           
298	  TRAP_LSU_FF       
299	} TRAP_INFO_e;
